#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long catalan[200005];

long long power(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

long long inv(long long a) {
    return power(a, MOD - 2);
}

int main() {
    int N, T;
    scanf("%d %d", &N, &T);
    int a[N], b[N];
    for (int i = 0; i < N; i++) scanf("%d", &a[i]);
    for (int i = 0; i < N; i++) scanf("%d", &b[i]);
    catalan[0] = 1;
    for (int i = 1; i <= 200000; i++) {
        catalan[i] = (catalan[i - 1] * (4 * i - 2)) % MOD;
        catalan[i] = (catalan[i] * inv(i + 1)) % MOD;
    }
    while (T--) {
        int L, R;
        scanf("%d %d", &L, &R);
        long long ans = 0;
        for (int i = L - 1; i < R; i++) {
            if (a[i] / 2 >= b[i]) {
                ans = (ans + catalan[a[i] / 2 - b[i]]) % MOD;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

